void delay_ms(unsigned int ms) {
    while (ms-- > 0) {
        asm("repeat #15998");
        asm("nop");
    }
}

void init_servos() {
    _RCDIV = 0;
    __builtin_write_OSCCONL(OSCCON & 0xbf); // Unlock PPS
    RPOR7bits.RP14R = 18;                    // Map RP14 to OC1 (servo1)
    RPOR6bits.RP13R = 19;                   // Map RP13 to OC2 (servo2)
    __builtin_write_OSCCONL(OSCCON | 0x40); // Lock PPS

    AD1PCFG = 0xFFFF;                        // Set all pins digital
    TRISBbits.TRISB14 = 0;                   // Set RP14 to output (servo1)
    TRISBbits.TRISB13 = 0;                   // Set RP13 to output (servo2)

    TMR3 = 0;                                // Reset timer
    PR3 = SERVO_PERIOD;                      // Set period
    T3CON = 0x8010;                          // Enable TON, prescale x8

    OC1RS = (SERVO_PERIOD / 4);              // Full period
    OC1CON = 0x000E;                         // Set OC1 to PWM mode
    OC1CONbits.OCFLT = 0;                    // Clear flag    
    
    OC2RS = 0;
    OC2CON = 0x000E;
    OC2CONbits.OCFLT = 0;
}

void setServo(unsigned int percent) {
    // Range of input is 0-65535
    // 0 degree position --> 1000
    // 180 degree position --> 5000
    
    // Need to convert that to 0-100% for the servo
    OC1RS = (unsigned int)(((unsigned long)percent*4000)/65535 + 1000);
}

void setServo2(unsigned int percent) {
    // Range of input is 0-65535
    // 0 degree position --> 1000
    // 180 degree position --> 5000
    
    // Need to convert that to 0-100% for the servo
    OC2RS = (unsigned int)(((unsigned long)(65535-percent)*4000)/65535 + 1000);
}

// Verified working and accurate
unsigned int distance(unsigned int x, unsigned int y) {
    // x and y from [0,511]
    unsigned int n0 = MAX(x,y); // Take max (1 cycle)
    n0 *= 5;
    n0 = (n0 >> 2); // Divide by 4
    // Now we have our initial guess, 1.25 times the max
    // Time to find number to take sqrt of
    unsigned long N = (unsigned long)x*x + (unsigned long)y*y;
    // Could split this part into its own sqrt function
    unsigned long dividend = (unsigned long)n0*(N*3+(unsigned long)n0*n0);
    unsigned int divisor = MAX(((N + (unsigned long)3*n0*n0) >> 6),1);
    unsigned int result = ((dividend/divisor) >> 6);
    
    return result;
}

unsigned int calculateInnerAngle(unsigned int x, unsigned int y) {
    return inner_angle_table[distance(x,y) - X_OFFSET];
}

// Change this to bit shifts rather than explicit multiplication
// TRIED AND IT FREAKED OUT
unsigned int calculateArctanIndex(unsigned int x, unsigned int y) {
    return ((long)y*65535/(MAX(x,1))*(ARCTAN_TABLE_SIZE - 1)/65535);
}

unsigned int calculateOuterAngle(unsigned int x, unsigned int y) {
    // The goal is to always keep (y/x) or (x/y) under 1. We can use trig identities to flip these around.
    if (y < x) {
        return 0x8000 + arctan_table[calculateArctanIndex(x,y)] - (calculateInnerAngle(x,y) >> 1);
    }
    return 0x0000 - arctan_table[calculateArctanIndex(y,x)] - (calculateInnerAngle(x,y) >> 1);
}

unsigned int raw_x = 512;       // Starting position for x
unsigned int raw_y = 512;       // Starting position for y
int direction = 0;            // 0: right, 1: up, 2: left, 3: down

void update_pos(void) {
    switch (direction) {
        case 0: // Move right
            if (raw_x < 900) {
                raw_x += 10;
            } else {
                direction = 1; // Change to moving up when reaching the right edge
            }
            break;
            
        case 1: // Move up
            if (raw_y < 900) {
                raw_y += 10;
            } else {
                direction = 2; // Change to moving left when reaching the top
            }
            break;
            
        case 2: // Move left
            if (raw_x > 512) {
                raw_x -= 10;
            } else {
                direction = 3; // Change to moving down when reaching the left edge
            }
            break;
            
        case 3: // Move down
            if (raw_y > 64) {
                raw_y -= 10;
            } else {
                direction = 0; // Change to moving right when reaching the bottom
            }
            break;
    }
}

int main(void) {
    
    init_servos();
    
    setupHeartbeat();
    initLCD();
    setDoubleHeight();
    // setROMC();
    
    char str[5];
    
    unsigned int x, y;
    unsigned int inner_angle_index;
    unsigned int arctan_index;
    unsigned int inner_angle, outer_angle;
    
    while (1) {
        update_pos();
        
        // raw_x, raw_y both [0,1023], from ADC. x limited to [64,512].
        // This number is arbitrary, works well for a piece of paper tho.
        x = MAX(X_OFFSET, (raw_x >> 1));
        y = (raw_y >> 1);
        
        inner_angle_index = distance(x,y);
        arctan_index = calculateArctanIndex(x,y);
        
        inner_angle = calculateInnerAngle(x,y);
        outer_angle = calculateOuterAngle(x,y);
        
        setServo(outer_angle);
        setServo2(inner_angle);
        
        // Sending to display
        lcd_cmd(0x00,0x01); // Clear display
        setCursor(0,0); // Move to first line
        
        unsignedIntToString(outer_angle/364, str);
        lcd_printStr(str);
        
        setCursor(2,0); // Move to first line
        
        unsignedIntToString(inner_angle/364, str);
        lcd_printStr(str);
        
        delay_ms(10); // Wait
        LATBbits.LATB15 ^= 1; // Toggle RB15 (heartbeat LED)
    }

    return 0;
}

